import React from "react";
import { Outlet, Link, useLocation } from "react-router-dom";

const AdminLayout = () => {
  const location = useLocation();

  const navItems = [
    { name: "Tổng quan", path: "/admin/dashboard" },
    { name: "Quản lý sản phẩm", path: "/admin/products" },
    { name: "Quản lý đơn hàng", path: "/admin/orders" },
    { name: "Quản lý danh mục", path: "/admin/categories" },
  ];

  return (
    <div className="flex min-h-screen bg-gray-50">
      {/* Sidebar */}
      <aside className="w-60 bg-white border-r border-gray-200 p-5">
        <h2 className="text-lg font-semibold text-gray-700 mb-5">
          DTP Flower Shop - Quản trị
        </h2>
        <nav className="flex flex-col gap-2">
          {navItems.map((item) => (
            <Link
              key={item.path}
              to={item.path}
              className={`px-3 py-2 rounded-lg transition ${
                location.pathname === item.path
                  ? "bg-green-100 text-green-700 font-medium"
                  : "text-gray-600 hover:bg-gray-100"
              }`}
            >
              {item.name}
            </Link>
          ))}
          <a
            href="/"
            className="mt-3 text-sm text-blue-500 hover:underline"
            target="_blank"
            rel="noreferrer"
          >
            Xem trang web
          </a>
        </nav>
      </aside>

      {/* Content */}
      <main className="flex-1 p-6 bg-gray-50 overflow-y-auto">
        <Outlet />
      </main>
    </div>
  );
};

export default AdminLayout;
